    #slice_output = 0
    DF_prep_BCx = pd.DataFrame()
    for slice in output: # we run by the all slices inside of the dictionary and store it in a dataset
        DF_prep_BCx=DF_prep_BCx.append(slice['Data']) #, ignore_index=True)
        #print(DF_prep_BCx)


    print("<--------")
    temp_list=[]
    intermediate_DF = pd.DataFrame()
