            slice_pos_mac = DF_prep_BCx.loc[DF_prep_BCx['Phenotype'] == 'Macrophage'];
            
            #slice_pos_mac = slice_pos_mac.loc[slice_pos_mac['Tissue Category'] != 'Glass']
            
            
