    fig.set_figwidth(20)
    plt.suptitle(str(Donor_name)+'_'+markersdiv[1], size = 16)
    #fig.show()
    fig.savefig(notebook_path+'/'+str(current_condition)+'/'+'_'+subcompartment +'_'+Donor_name+markersdiv[1]+'_before_after_BCx_'+'.pdf',   bbox_inches='tight');
    plt.show()
    
    
    
