    # because of the merge of two DF, the name of the column requires "_x" element
    sns.distplot(slice['Data'][markersdiv[0]], hist = False, kde = True,
                kde_kws = {'shade': True, 'linewidth': 2},
                label = "Non-Normal", color ="black", ax = ax[0])
    sns.distplot(x_ax, hist = False, kde = True,
                kde_kws = {'shade': True, 'linewidth': 2},
                label = "Normal", color ="black", ax = ax[1])

