            fitted_data, fitted_lambda = stats.boxcox(slice_pos[str(markersdiv_)]);
            print(len(fitted_data))
            print(fitted_data)
            fitted_data = stats.zscore(fitted_data)
            slice_pos[str(markersdiv_) + '_BCx'] = fitted_data;
