def interaction_subset(df, cell1, cell2, min_count):#
    # used to be , min_count=20):, need to be reduced in order to take into consideration
    # the rare subpopulation of cells as CD4 and CD8
    # to make less strict for the cases when there are no cells in one subfile (originally >20)
    pcf_table = df[(((df['Cell_one']==cell1) & (df['Cell_two']==cell2)) | ((df['Cell_one']==cell2) & (df['Cell_two']==cell1)) ) & (df['min_count'] > min_count)]
    pcf_table = pcf_table[pcf_table['PCF'] != 'NA']
    return pcf_table


